import json
import pandas as pd
import re

# Load business collection result from file path provided in var_call_JmH66U9NAea1QQWm75JdhDUC
path = var_call_JmH66U9NAea1QQWm75JdhDUC
with open(path, 'r') as f:
    businesses = json.load(f)

# Load review aggregation from var_call_D91O35CFQVckdTKnyoNa0pYY
reviews_agg = var_call_D91O35CFQVckdTKnyoNa0pYY

biz_rows = []
for b in businesses:
    biz_id = b.get('business_id')
    attrs = b.get('attributes')
    desc = b.get('description') or ''
    wifi_norm = None
    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi') if 'WiFi' in attrs else None
        if wifi_val is not None:
            s = str(wifi_val)
            # remove leading u' or u" if present
            if s.startswith("u'") or s.startswith('u"'):
                s = s[2:]
            # strip surrounding quotes and spaces
            s = s.strip("\"' ")
            wifi_norm = s.lower()
    # extract state from description
    state = None
    m = re.search(r'in [^,]+,\s*([A-Z]{2})', desc)
    if not m:
        m = re.search(r',\s*([A-Z]{2})\s*,', desc)
    if m:
        state = m.group(1)
    biz_rows.append({'business_id': biz_id, 'wifi': wifi_norm, 'state': state})

df_biz = pd.DataFrame(biz_rows)
negatives = set(['no','none','false','na','n'])

def wifi_offered_val(x):
    if x is None:
        return False
    try:
        return False if x in negatives else True
    except:
        return False

if 'wifi' not in df_biz.columns:
    df_biz['wifi'] = None

df_biz['wifi_offered'] = df_biz['wifi'].apply(wifi_offered_val)

state_counts = df_biz[df_biz['state'].notnull() & df_biz['wifi_offered']].groupby('state').size().reset_index(name='count')

if state_counts.empty:
    result = {'state': None, 'wifi_business_count': 0, 'average_rating': None}
else:
    top = state_counts.sort_values('count', ascending=False).iloc[0]
    top_state = top['state']
    top_count = int(top['count'])
    top_biz = df_biz[(df_biz['state']==top_state) & (df_biz['wifi_offered'])]['business_id'].tolist()
    biz_to_ref = {b: b.replace('businessid_', 'businessref_') for b in top_biz}

    rev_lookup = {}
    for r in reviews_agg:
        bref = r.get('business_ref')
        avg_raw = r.get('avg_rating')
        cnt_raw = r.get('review_count')
        try:
            avg = float(avg_raw)
        except:
            avg = None
        try:
            cnt = int(cnt_raw)
        except:
            cnt = 0
        rev_lookup[bref] = {'avg_rating': avg, 'review_count': cnt}

    total_reviews = 0
    weighted_rating_sum = 0.0
    for b, bref in biz_to_ref.items():
        info = rev_lookup.get(bref)
        if info and info['avg_rating'] is not None and info['review_count']>0:
            rc = info['review_count']
            ar = info['avg_rating']
            total_reviews += rc
            weighted_rating_sum += ar * rc
    if total_reviews>0:
        overall_avg = weighted_rating_sum / total_reviews
    else:
        overall_avg = None
    if overall_avg is not None:
        overall_avg = round(overall_avg, 3)
    result = {'state': top_state, 'wifi_business_count': top_count, 'average_rating': overall_avg}

print('__RESULT__:')
print(json.dumps(result))

